scwin.onpageload = function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.vPreDate = scwin.vCurDate.substring(0, 6) + "01";

    scwin.params = $c.data.getParameter();
    if (scwin.params != null) {
        if (scwin.params["certiNo"] != null) {
            scwin.certiNo = scwin.params["certiNo"];
        }
        if (scwin.params["link"] != null) {
            scwin.link = scwin.params["link"];
        }
        if (scwin.params["flag"] != null) {
            scwin.flag = scwin.params["flag"];
        }
    }

    scwin.f_Set("INIT");
};

scwin.onUdcCompleted = function() {
    ica_qryConDtFm.setValue(scwin.vPreDate);
    ica_qryConDtTo.setValue(scwin.vCurDate);
    ed_confirmDt.setValue(scwin.vCurDate);

    ed_bilgLodeptCd.setFocus();

    rd_prebilgYn.setValue("0");
    rd_fullEmptyClsCd.setValue("");
    rd_taxnClsCd.setSelectedIndex(0);

    txt_printPage.setValue("1");

    scwin.f_RetrieveFmalPattern();
    scwin.f_RetrieveDtlFmalPattern();

    if (scwin.certiNo != "" && scwin.link == "true") {
        scwin.f_CertiRetrieve();
    }

    if (scwin.flag != "") {
        // TODO: parent frame ds_orderselling_con copy logic
        scwin.f_WholeRetrieve();
    }
};

scwin.f_Set = function(gubun) {
    switch (gubun) {
        case "INIT":
            break;
    }
};

scwin.f_WholeRetrieve = function() {
    ed_bilgLodeptCd.setValue(dma_orderselling_con.get("bilgLodeptCd"));
    scwin.f_openCommonPopUp(1, ed_bilgLodeptCd.getValue(), txt_bilgLodeptNm.getValue(), "T", "T");
    ed_lineCd.setValue(dma_orderselling_con.get("lineCd"));
    scwin.ed_bilgClntNo = dma_orderselling_con.get("bilgClntNo");
    scwin.txt_bilgClntNm = dma_orderselling_con.get("bilgClntNm");
    lc_qryConKnd.setValue(dma_orderselling_con.get("qryConKnd"));

    if (dma_orderselling_con.get("sumQryYn") == "Y") {
        chb_sumDc.setValue("Y");
    } else {
        chb_sumDc.setValue("");
    }

    // TODO: div_qryConKnd1/div_qryConKnd2 display toggle logic

    lc_impExpDomesticClsCd.setValue(dma_orderselling_con.get("impExpDomesticClsCd"));
    // TODO: ed_qryConCd mapping
    ica_qryConDtFm.setValue(dma_orderselling_con.get("qryConDtFm"));
    ica_qryConDtTo.setValue(dma_orderselling_con.get("qryConDtTo"));
    lc_odrKndCd.setValue(dma_orderselling_con.get("odrKndCd"));
    // TODO: ed_qryConCd2 mapping
    rd_taxnClsCd.setValue(dma_orderselling_con.get("taxnClsCd"));
    lc_fmlaPatternCd.setValue(dma_orderselling_con.get("fmlaPatternCd"));

    scwin.f_Retrieve();
};

scwin.f_Retrieve = async function() {
    let qryConKndVal = lc_qryConKnd.getValue();
    if (qryConKndVal == "배차" || qryConKndVal == "오더일자" || qryConKndVal == "청구인식일" || qryConKndVal == "실적일자") {
        let chk = await $c.gus.cfValidate([ed_bilgLodeptCd, ed_lineCd, lc_fmlaPatternCd, ica_qryConDtFm, ica_qryConDtTo]);
        if (!chk) return;
    } else {
        let chk = await $c.gus.cfValidate([ed_bilgLodeptCd, ed_lineCd, lc_fmlaPatternCd]);
        if (!chk) return;
    }

    let chkAppendVal = chb_chkAppend.getValue();
    if (chkAppendVal != "") {
        if (ds_certidetail.getRowCount() > 0 && ed_lineCd.getValue() != dma_certicommon.get("lineCd")) {
            await $c.gus.cfAlertMsg(MSG_FS_WRN_014);
            return;
        }
        if (dma_certicommon.get("sellVatNo") != "") {
            await $c.gus.cfAlertMsg(MSG_FS_WRN_015);
            return;
        }
    }

    if (!$c.gus.cfIsAfterDate(ica_qryConDtFm.getValue(), ica_qryConDtTo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }

    dma_orderselling_con.set("bilgLodeptCd", ed_bilgLodeptCd.getValue());
    dma_orderselling_con.set("qryConCd", "");
    dma_orderselling_con.set("qryConDtFm", ica_qryConDtFm.getValue());
    dma_orderselling_con.set("qryConDtTo", ica_qryConDtTo.getValue());

    if (chkAppendVal != "") {
        if (ds_certidetail.getRowCount() > 0) {
            dma_orderselling_con.set("lineCd", dma_certicommon.get("lineCd"));
        } else {
            dma_orderselling_con.set("lineCd", ed_lineCd.getValue());
        }
    } else {
        dma_orderselling_con.set("lineCd", ed_lineCd.getValue());
    }

    dma_orderselling_con.set("vsslCd", ed_vsslCd.getValue());
    dma_orderselling_con.set("tsVsslCd", ed_tsVsslCd.getValue());
    dma_orderselling_con.set("onWrkPlCd", ed_onWrkPlCd.getValue());
    dma_orderselling_con.set("offWrkPlCd", ed_offWrkPlCd.getValue());
    dma_orderselling_con.set("taxnClsCd", rd_taxnClsCd.getValue());
    dma_orderselling_con.set("qryConKnd", lc_qryConKnd.getValue());
    dma_orderselling_con.set("impExpDomesticClsCd", lc_impExpDomesticClsCd.getValue());
    dma_orderselling_con.set("portcnt", ed_portcnt.getValue());
    dma_orderselling_con.set("tsPortcnt", ed_tsPortcnt.getValue());
    dma_orderselling_con.set("cntrSizCd", lc_cntrSizCd.getValue());
    dma_orderselling_con.set("fullEmptyClsCd", rd_fullEmptyClsCd.getValue());
    dma_orderselling_con.set("sellItemCd", lc_sellItemCd.getValue());
    dma_orderselling_con.set("certiPatternCd", scwin.certiPatternCd);
    dma_orderselling_con.set("receptClsCd", scwin.receptClsCd);
    dma_orderselling_con.set("prebilgYn", scwin.prebilgYn);
    dma_orderselling_con.set("pgmId", scwin.pgmId);
    dma_orderselling_con.set("fmlaClsCd", scwin.fmlaClsCd);
    dma_orderselling_con.set("fmlaPatternCd", lc_fmlaPatternCd.getValue());

    let cntrTypCdVal = lc_cntrTypCd.getValue();
    if (cntrTypCdVal == "전체") {
        cntrTypCdVal = "";
    }
    dma_orderselling_con.set("cntrTypCd", cntrTypCdVal);
    dma_orderselling_con.set("transDst", lc_transDst.getValue());
    dma_orderselling_con.set("odrKndCd", lc_odrKndCd.getValue());
    dma_orderselling_con.set("transCargoClsCd", "C");
    dma_orderselling_con.set("gubun", "LINE");
    dma_orderselling_con.set("odrLineCd", ed_odrLineCd.getValue());

    let chkSumDcVal = chb_sumDc.getValue();
    if (chkSumDcVal != "") {
        dma_orderselling_con.set("chkSumDc", "Y");
    } else {
        dma_orderselling_con.set("chkSumDc", "N");
    }

    dma_orderselling_con.set("tpoNo", txt_tpoNo.getValue());

    if (chkAppendVal != "") {
        await $c.sbm.execute(sbm_appendrow_retrieve);
    } else {
        await $c.sbm.execute(sbm_orderselling_retrieve);
    }
};

