scwin.f_openPopUpGrid = function(ds, row, cdColid, nmColid, gubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    let pCode = "";
    let pName = "";
    let pWtitleSearch = null;
    let pWhere = null;
    let pSelectID = "";

    pCode = ds.getCellData(row, cdColid);

    if (gubun == 1) {
        pSelectID = "retrieveVsslCdInfo";
        pWtitleSearch = "모선,코드,코드명";
    }

    let rtnList = $c.gus.cfCommonPopUp(pSelectID,
        pCode,
        pName,
        pWinCloseTF,
        null,
        null,
        null,
        null,
        pWhere,
        null,
        null,
        null,
        null,
        null,
        pAllSearchTF,
        pWtitleSearch,
        pNoDataCloseTF);

    $c.gus.cfSetGridReturnValue(rtnList, ds, row, cdColid, nmColid);
};

scwin.f_MySave = async function(separation) {
    if (ds_certidetail.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["DATA"]);
        return;
    }

    if (scwin.addflag != "MOD" && scwin.appflag == "TRUE") {
        scwin.addflag = "REG";
    } else if (scwin.addflag == "MOD" && scwin.appflag == "TRUE") {
        scwin.addflag = "MOD";
    }

    scwin.delflag = "";

    if (scwin.addflag == "REG") {
        if (separation == "true") {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["CERTI DATA"]);
            return;
        } else {
            let chk = await $c.gus.cfValidate([ed_confirmDt, dtl_billTitleNm]);
            if (!chk) return;
        }
    } else if (scwin.addflag == "" || scwin.addflag == "MOD") {
        let chk = await $c.gus.cfValidate([ed_certiNo, ed_confirmDt, dtl_billTitleNm]);
        if (!chk) return;
        if (separation == "true") {
            let checkflag = "";
            for (let i = 0; i < ds_certidetail.getRowCount(); i++) {
                if (ds_certidetail.getCellData(i, "choice") != "T") {
                    checkflag = "F";
                }
            }
            if (checkflag != "F") {
                await $c.gus.cfAlertMsg(MSG_FS_WRN_003);
                return;
            }
        }
    }

    dma_certicommon.set("fmlaClsCd", scwin.fmlaClsCd);
    dma_certicommon.set("upperCertiNo", scwin.upperCertiNo);
    dma_certicommon.set("pldgMgntNo", scwin.pldgMgntNo);
    dma_certicommon.set("pgmId", scwin.pgmId);

    scwin.f_Save(separation);
};

scwin.f_Save = function(separation) {
    // TODO: f_Save implementation from bilgcommon include
};

scwin.f_PostSumAmt = function(i) {
    if (i == 0) {
        scwin.Wt20E = 0;
        scwin.Wt20F = 0;
        scwin.Wt40E = 0;
        scwin.Wt40F = 0;
        scwin.Wt45E = 0;
        scwin.Wt45F = 0;
    }
    if (ds_certidetail.getCellData(i, "choice") == "T") {
        let cntrSiz = ds_certidetail.getCellData(i, "cntrSizCd");
        let fullEmpty = ds_certidetail.getCellData(i, "fullEmptyClsCd");
        let sellVol = Number(ds_certidetail.getCellData(i, "sellVol"));
        if (cntrSiz == "20" && fullEmpty == "E") {
            scwin.Wt20E = scwin.Wt20E + sellVol;
        } else if (cntrSiz == "20" && fullEmpty == "F") {
            scwin.Wt20F = scwin.Wt20F + sellVol;
        } else if (cntrSiz == "40" && fullEmpty == "E") {
            scwin.Wt40E = scwin.Wt40E + sellVol;
        } else if (cntrSiz == "40" && fullEmpty == "F") {
            scwin.Wt40F = scwin.Wt40F + sellVol;
        } else if (cntrSiz == "45" && fullEmpty == "E") {
            scwin.Wt45E = scwin.Wt45E + sellVol;
        } else if (cntrSiz == "45" && fullEmpty == "F") {
            scwin.Wt45F = scwin.Wt45F + sellVol;
        }
    }

    dtl_Wt20E.setValue(scwin.Wt20E);
    dtl_Wt20F.setValue(scwin.Wt20F);
    dtl_Wt40E.setValue(scwin.Wt40E);
    dtl_Wt40F.setValue(scwin.Wt40F);
    dtl_Wt45E.setValue(scwin.Wt45E);
    dtl_Wt45F.setValue(scwin.Wt45F);
};

scwin.f_SumAmt = function() {
    for (let i = 0; i < ds_certidetail.getRowCount(); i++) {
        scwin.f_PostSumAmt(i);
    }
};

