scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search, [ed_bilgLodeptCd, txt_bilgLodeptNm, ed_lineCd, lc_qryConKnd, ica_qryConDtFm, ica_qryConDtTo, lc_fmlaPatternCd, lc_impExpDomesticClsCd, lc_sellItemCd, txt_tpoNo]);
};

