};

scwin.f_multiChoice = function() {
    if (scwin.chkFlag) {
        for (let i = 0; i < ds_certidetail.getRowCount(); i++) {
            if (gr_certidetail.getCheckedIndex().indexOf(i) > -1) {
                ds_certidetail.setCellData(i, "choice", "T");
            }
        }
    } else {
        for (let i = 0; i < ds_certidetail.getRowCount(); i++) {
            if (gr_certidetail.getCheckedIndex().indexOf(i) > -1) {
                ds_certidetail.setCellData(i, "choice", "F");
            }
        }
        scwin.chkFlag = true;
        return;
    }
    scwin.chkFlag = false;
};

